"use client";
import React, { useState } from 'react';
import Link from 'next/link';

export default function Header() {
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const toggleMenu = () => {
    setIsMenuOpen(!isMenuOpen);
  };

  return (
    <header>
      <div className="container">
        <nav className="navbar">
          <div className="logo-container">
            <img src="/Images/Veltech.jpeg" alt="University" className="funding-logo" />
            <img src="/Images/Zf.jpeg" alt="Company" className="funding-logo" />
          </div>

          <ul className={`nav-links ${isMenuOpen ? 'active' : ''}`}>
            <li className="nav-item" onClick={() => setIsMenuOpen(false)}><Link href="/#home">Home</Link></li>
            <li className="nav-item" onClick={() => setIsMenuOpen(false)}><Link href="/#about">About</Link></li>
            <li className="nav-item" onClick={() => setIsMenuOpen(false)}><Link href="/#leadership">Leadership</Link></li>
            <li className="nav-item" onClick={() => setIsMenuOpen(false)}><Link href="/#gallery">Lab Gallery</Link></li>
            <li className="nav-item" onClick={() => setIsMenuOpen(false)}><Link href="/lab-images">Photo Stream</Link></li>
            <li className="nav-item" onClick={() => setIsMenuOpen(false)}><Link href="/#workshops">Workshops</Link></li>
            <li className="nav-item" onClick={() => setIsMenuOpen(false)}><Link href="/#projects">Projects</Link></li>
            <li className="nav-item" onClick={() => setIsMenuOpen(false)}><Link href="/#pcbs">Latest PCBs</Link></li>
            <li className="nav-item" onClick={() => setIsMenuOpen(false)}><Link href="/#members">Members</Link></li>
            <li className="nav-item" onClick={() => setIsMenuOpen(false)}><Link href="/#contact">Contact</Link></li>
          </ul>

          <div className="menu-toggle" onClick={toggleMenu}>
            <i className={`fas ${isMenuOpen ? 'fa-times' : 'fa-bars'}`}></i>
          </div>
        </nav>
      </div>
    </header>
  );
}